package com.trademaster.ims.mobile.orders.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="customer_order_cancellation_requests",uniqueConstraints={@UniqueConstraint(name="uk_cancel_idempotency",columnNames={"customer_account_id","idempotency_key"})},indexes={@Index(name="idx_cancel_order",columnList="order_id")})
public class CustomerOrderCancellationRequest{public enum ReasonCode{ORDERED_BY_MISTAKE,NEED_TO_CHANGE_ADDRESS,NEED_TO_CHANGE_ITEMS,FOUND_BETTER_PRICE,DELIVERY_TIME_TOO_LONG,OTHER}public enum Status{REQUESTED,UNDER_REVIEW,APPROVED,REJECTED,WITHDRAWN}@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="order_id",nullable=false)private Long orderId;@Column(name="customer_account_id",nullable=false)private Long accountId;@Enumerated(EnumType.STRING)@Column(name="reason_code",nullable=false,length=40)private ReasonCode reasonCode;@Column(name="reason_text",length=500)private String reasonText;@Enumerated(EnumType.STRING)@Column(nullable=false,length=30)private Status status=Status.REQUESTED;@Column(name="idempotency_key",nullable=false,length=100)private String idempotencyKey;@Column(name="requested_at",nullable=false)private Instant requestedAt;@Column(name="reviewed_at")private Instant reviewedAt;@Column(name="resolution_note",length=500)private String resolutionNote;@Column(name="created_at",nullable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;@Version private Long version;@PrePersist void p(){Instant n=Instant.now();if(requestedAt==null)requestedAt=n;createdAt=n;updatedAt=n;}@PreUpdate void u(){updatedAt=Instant.now();}
public Long getId(){return id;}public Long getOrderId(){return orderId;}public Long getAccountId(){return accountId;}public ReasonCode getReasonCode(){return reasonCode;}public String getReasonText(){return reasonText;}public Status getStatus(){return status;}public String getIdempotencyKey(){return idempotencyKey;}public Instant getRequestedAt(){return requestedAt;}public String getResolutionNote(){return resolutionNote;}public void setOrderId(Long v){orderId=v;}public void setAccountId(Long v){accountId=v;}public void setReasonCode(ReasonCode v){reasonCode=v;}public void setReasonText(String v){reasonText=v;}public void setStatus(Status v){status=v;}public void setIdempotencyKey(String v){idempotencyKey=v;}public void setRequestedAt(Instant v){requestedAt=v;}public void setResolutionNote(String v){resolutionNote=v;}}
